def init_db() -> None:
    with engine.begin() as conn:
        conn.execute(
            text(
                """
                CREATE TABLE IF NOT EXISTS widgets (
                    id INTEGER PRIMARY KEY AUTOINCREMENT,
                    name TEXT NOT NULL,
                    created_at TEXT NOT NULL
                )
                """
            )
        )

@app.get("/health")
def health():
    return jsonify({"status": "ok", "service": APP_NAME, "environment": ENVIRONMENT})

@app.post("/widgets")
def create_widget():
    data = request.get_json(silent=True) or {}
    name = data.get("name") or "unnamed"
    now = time.strftime("%Y-%m-%dT%H:%M:%SZ", time.gmtime())

    with elasticapm.capture_span("db.insert_widget", span_type="db", span_subtype="sql", span_action="insert"):
        with engine.begin() as conn:
            conn.execute(
                text("INSERT INTO widgets (name, created_at) VALUES (:name, :created_at)"),
                {"name": name, "created_at": now},
            )

    return jsonify({"ok": True, "name": name, "created_at": now}), 201

@app.get("/widgets")
def list_widgets():
    limit = int(request.args.get("limit", "50"))
    with elasticapm.capture_span("db.select_widgets", span_type="db", span_subtype="sql", span_action="select"):
        with engine.connect() as conn:
            rows = conn.execute(
                text("SELECT id, name, created_at FROM widgets ORDER BY id DESC LIMIT :limit"),
                {"limit": limit},
            ).mappings().all()
    return jsonify({"count": len(rows), "items": [dict(r) for r in rows]})

@app.get("/widgets/<int:widget_id>")
def get_widget(widget_id: int):
    with elasticapm.capture_span("db.select_widget_by_id", span_type="db", span_subtype="sql", span_action="select"):
        with engine.connect() as conn:
            row = conn.execute(
                text("SELECT id, name, created_at FROM widgets WHERE id = :id"),
                {"id": widget_id},
            ).mappings().first()
    if not row:
        return jsonify({"error": "not_found"}), 404
    return jsonify(dict(row))

